import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What are common factors?", a: "Common factors are numbers that divide two or more numbers evenly. For example, common factors of 12 and 18 include 1, 2, 3, and 6." },
  { q: "How do you find all common factors of two numbers?", a: "List all factors of each number, then keep the values that appear in every list." },
  { q: "What is the difference between common factors and GCF?", a: "Common factors are all shared factors. The GCF is the greatest, or largest, common factor." },
  { q: "How are common factors used in simplifying fractions?", a: "Divide the numerator and denominator by a common factor. Dividing by the GCF simplifies the fraction completely in one step." },
  { q: "Can three numbers have common factors?", a: "Yes. Three or more numbers have common factors if the same factor divides all of them evenly." },
];

const factorsOf = (n: number) => {
  const factors: number[] = [];
  for (let i = 1; i <= Math.sqrt(n); i++) if (n % i === 0) { factors.push(i); if (i !== n / i) factors.push(n / i); }
  return factors.sort((a, b) => a - b);
};

export default function CommonFactorCalculator() {
  const [input, setInput] = useState("24, 36, 60");
  const result = useMemo(() => {
    const nums = input.split(/[\s,;]+/).map((n) => Math.abs(Math.trunc(Number(n)))).filter((n) => Number.isFinite(n) && n > 0).slice(0, 10);
    if (nums.length < 2) return null;
    const lists = nums.map(factorsOf);
    const common = lists[0].filter((f) => lists.every((list) => list.includes(f)));
    return { nums, lists, common, gcf: common[common.length - 1] || 1 };
  }, [input]);

  return (
    <>
      <SEOHead title="Free Common Factor Calculator Online - Find All Common Factors of Any Numbers Instantly | CalcHive" description="Free online common factor calculator. Find all common factors of two or more numbers with step by step solution instantly. 100% free for math students and everyone, no signup required." canonical="/common-factor-calculator" keywords="free common factor calculator, common factors of two numbers calculator free, shared factors calculator free online, find common factors free, GCF factor calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Common Factor Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free common factor calculator to find common factors free and identify the GCF.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <label htmlFor="common-factor-input" className="text-sm font-semibold text-foreground block mb-2">Numbers, up to 10</label>
          <input id="common-factor-input" value={input} onChange={(e) => setInput(e.target.value)} className="w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
          {result ? <motion.div key={input} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }} className="mt-8">
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Greatest Common Factor</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-common-factor">{result.gcf}</p><p className="text-white/70 text-sm mt-1">Common factors: {result.common.join(", ")}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.nums.map((n, i) => `${n}: ${result.lists[i].join(", ")}`).join("; ")}. Shared factors are {result.common.join(", ")}, so the GCF is {result.gcf}.</p></div>
          </motion.div> : <p className="text-center text-muted-foreground py-6">Enter at least two positive integers.</p>}
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Find All Common Factors of Any Numbers for Free</h2><p className="text-muted-foreground leading-relaxed">Enter two or more numbers and this shared factors calculator free online lists each factor set and highlights the shared factors.</p><h2 className="text-2xl font-bold text-foreground">How Common Factors and GCF Are Related</h2><p className="text-muted-foreground leading-relaxed">The GCF is simply the largest number in the list of common factors.</p><h2 className="text-2xl font-bold text-foreground">Free Shared Factor Finder for Math Students</h2><p className="text-muted-foreground leading-relaxed">Use this GCF factor calculator free for fractions, divisibility, and number theory practice.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/common-factor-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


